using UnityEngine;
using UnityEditor;
using UnityEngine.SceneManagement;
using UnityEditor.SceneManagement;
using System.Collections.Generic;

internal class CommandScript : IRunCommand
{
    public void Execute(ExecutionResult result)
    {
        string scenePath = "Assets/Scenes/SampleScene.unity";
        Scene scene = EditorSceneManager.OpenScene(scenePath, OpenSceneMode.Additive);

        GameObject panel = GameObject.Find("LessonListPanel");
        if (panel == null)
        {
            // Try finding by path or inactive
            foreach (GameObject go in scene.GetRootGameObjects())
            {
                if (go.name == "LessonListPanel") { panel = go; break; }
                // Recursive search
                panel = FindChildRecursive(go, "LessonListPanel");
                if (panel != null) break;
            }
        }

        if (panel != null)
        {
            result.Log("Found LessonListPanel at {0}", panel.transform.root.name);
            Component[] components = panel.GetComponents<Component>();
            for (int i = 0; i < components.Length; i++)
            {
                if (components[i] == null)
                {
                    result.LogWarning("Missing script at index {0} on {1}", i, panel.name);
                }
                else
                {
                    result.Log("Component {0}: {1}", i, components[i].GetType().Name);
                }
            }
        }
        else
        {
            result.LogError("Could not find LessonListPanel in {0}", scenePath);
        }

        EditorSceneManager.CloseScene(scene, true);
    }

    private GameObject FindChildRecursive(GameObject parent, string name)
    {
        foreach (Transform child in parent.transform)
        {
            if (child.name == name) return child.gameObject;
            GameObject found = FindChildRecursive(child.gameObject, name);
            if (found != null) return found;
        }
        return null;
    }
}

